/* global define */
var define
define(["jquery", "core/ajax", "core/notification"], ($, ajax, notification) => ({
  init: (config) => {
    var pdfDoc = null,
      pageNum = 1,
      pageRendering = false,
      pageNumPending = null,
      scale = 1.5,
      canvas = document.getElementById("pdf-canvas")
    if (!canvas) return void console.error("[v0] PDF canvas element not found")
    var ctx = canvas.getContext("2d"),
      fileurl = config.fileurl,
      enablecopying = config.enablecopying,
      enabledownload = config.enabledownload,
      enablesummarize = config.enablesummarize,
      contextid = config.contextid,
      filecaid = config.filecaid,
      script = document.createElement("script")

    function renderPage(num) {
      pageRendering = true
      pdfDoc.getPage(num).then((page) => {
        var viewport = page.getViewport({ scale: scale })
        canvas.height = viewport.height
        canvas.width = viewport.width
        var renderContext = { canvasContext: ctx, viewport: viewport },
          renderTask = page.render(renderContext)
        renderTask.promise.then(() => {
          pageRendering = false
          if (pageNumPending !== null) {
            renderPage(pageNumPending)
            pageNumPending = null
          }
        })
      })
      $("#pdf-page-info").text("Page " + num + " / " + pdfDoc.numPages)
    }

    function queueRenderPage(num) {
      if (pageRendering) {
        pageNumPending = num
      } else {
        renderPage(num)
      }
    }

    function onPrevPage() {
      if (pageNum > 1) {
        pageNum--
        queueRenderPage(pageNum)
      }
    }

    function onNextPage() {
      if (pageNum < pdfDoc.numPages) {
        pageNum++
        queueRenderPage(pageNum)
      }
    }

    function extractPdfText() {
      var textPromises = []
      for (var i = 1; i <= pdfDoc.numPages; i++) {
        textPromises.push(
          pdfDoc
            .getPage(i)
            .then((page) => page.getTextContent())
            .then((textContent) => textContent.items.map((item) => item.str).join(" ")),
        )
      }
      return Promise.all(textPromises).then((pages) => pages.join("\n"))
    }

    function summarizeDocument() {
      var $btn = $("#summarize-btn"),
        $result = $("#summary-result")
      $btn.prop("disabled", true).text("Summarizing...")
      $result.hide()
      extractPdfText().then((fullText) => {
        var promises = ajax.call([
          {
            methodname: "mod_fileca_generate_summary",
            args: { contextid: contextid, filecaid: filecaid, content: fullText.substring(0, 10000) },
          },
        ])
        promises[0]
          .done((response) => {
            if (response.success) {
              $result
                .html('<div class="alert alert-success"><h4>Summary</h4><p>' + response.summary + "</p></div>")
                .show()
            } else {
              notification.addNotification({ message: "Failed to generate summary", type: "error" })
            }
          })
          .fail(() => {
            notification.addNotification({ message: "Failed to generate summary", type: "error" })
          })
          .always(() => {
            $btn.prop("disabled", false).text("Summarize")
          })
      })
    }

    script.src = "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js"
    script.onload = () => {
      window.pdfjsLib.GlobalWorkerOptions.workerSrc =
        "https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js"
      console.log("[v0] PDF.js loaded, loading PDF from:", fileurl)
      var loadingTask = window.pdfjsLib.getDocument(fileurl)
      loadingTask.promise
        .then((pdf) => {
          pdfDoc = pdf
          console.log("[v0] PDF loaded successfully, pages:", pdf.numPages)
          renderPage(pageNum)
        })
        .catch((error) => {
          console.error("[v0] Error loading PDF:", error)
        })
    }
    document.head.appendChild(script)
    $("#pdf-prev").on("click", onPrevPage)
    $("#pdf-next").on("click", onNextPage)
    if (enablesummarize) {
      $("#summarize-btn").on("click", summarizeDocument)
    }
    if (!enablecopying) {
      $("#pdf-container").css({
        "-webkit-user-select": "none",
        "-moz-user-select": "none",
        "-ms-user-select": "none",
        "user-select": "none",
      })
      $("#pdf-container").on("copy", (e) => {
        e.preventDefault()
        return false
      })
    }
    if (!enabledownload) {
      $("#pdf-container").on("contextmenu", (e) => {
        e.preventDefault()
        return false
      })
    }
  },
}))
